mapper.select:
SELECT id, order_id, nuonuo_serial_no, tenant_id, status, req_payload, res_payload, error_msg, retry_count, created_at, updated_at
FROM invoice_record
WHERE order_id = #{orderId}

SELECT id, order_id, nuonuo_serial_no, tenant_id, status, req_payload, res_payload, error_msg, retry_count, created_at, updated_at
FROM invoice_record
WHERE nuonuo_serial_no = #{nuonuoSerialNo}

mapper.update:
UPDATE invoice_record
SET status = #{newStatus},
    updated_at = NOW()
WHERE order_id = #{orderId}
  AND status = #{oldStatus}

mapper.select:
SELECT id, order_id, nuonuo_serial_no, tenant_id, status, req_payload, res_payload, error_msg, retry_count, created_at, updated_at
FROM invoice_record
WHERE status IN ('WAIT_CALLBACK', 'RED_WAIT_CALLBACK')
  AND updated_at < #{threshold}
LIMIT #{limit}

SELECT id, order_id, nuonuo_serial_no, tenant_id, status, req_payload, res_payload, error_msg, retry_count, created_at, updated_at
FROM invoice_record
WHERE status IN ('FAIL', 'RED_FAIL')
  AND updated_at < #{threshold}
  AND retry_count < #{maxRetryCount}
LIMIT #{limit}

mapper.update:
UPDATE invoice_record
SET status = #{newStatus},
    retry_count = retry_count + 1,
    updated_at = NOW()
WHERE order_id = #{orderId}
  AND status = #{oldStatus}

UPDATE invoice_record
SET nuonuo_serial_no = #{nuonuoSerialNo},
    status = #{newStatus},
    updated_at = NOW()
WHERE order_id = #{orderId}
  AND status = #{oldStatus}
